(function(global) {
  'use strict';
  
  // 检查是否已经从 CDN 加载了 html2canvas
  if (global.html2canvas) {
    console.log('🖼️ html2canvas 已从 CDN 加载');
    return;
  }
  
  // 显示提示消息
  console.warn('⚠️ html2canvas 库未找到，请从以下地址下载：https://cdnjs.cloudflare.com/ajax/libs/html2canvas/1.4.1/html2canvas.min.js');
  console.warn('将下载的内容保存到 libs/html2canvas.min.js 文件');
  
})(typeof window !== 'undefined' ? window : this);